<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Wiki-Linux Interactive Dashboard</title>
    <style>
        :root {
            --bg-primary: #1e1e1e;
            --bg-secondary: #2d2d2d;
            --text-primary: #e0e0e0;
            --text-secondary: #a0a0a0;
            --accent: #4a9eff;
            --success: #4caf50;
            --warning: #ff9800;
            --error: #f44336;
        }

        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            background: var(--bg-primary);
            color: var(--text-primary);
            padding: 20px;
            line-height: 1.6;
        }

        .container {
            max-width: 1200px;
            margin: 0 auto;
        }

        header {
            text-align: center;
            padding: 30px 0;
            border-bottom: 2px solid var(--accent);
            margin-bottom: 30px;
        }

        h1 {
            font-size: 2.5em;
            margin-bottom: 10px;
            color: var(--accent);
        }

        .subtitle {
            color: var(--text-secondary);
            font-size: 1.1em;
        }

        .grid {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
            gap: 20px;
            margin-bottom: 30px;
        }

        .card {
            background: var(--bg-secondary);
            border-radius: 10px;
            padding: 20px;
            box-shadow: 0 4px 6px rgba(0,0,0,0.3);
            transition: transform 0.2s, box-shadow 0.2s;
        }

        .card:hover {
            transform: translateY(-5px);
            box-shadow: 0 6px 12px rgba(0,0,0,0.4);
        }

        .card h2 {
            color: var(--accent);
            margin-bottom: 15px;
            font-size: 1.5em;
            border-bottom: 1px solid var(--text-secondary);
            padding-bottom: 10px;
        }

        .stat {
            display: flex;
            justify-content: space-between;
            padding: 10px 0;
            border-bottom: 1px solid rgba(255,255,255,0.1);
        }

        .stat:last-child {
            border-bottom: none;
        }

        .stat-label {
            color: var(--text-secondary);
        }

        .stat-value {
            font-weight: bold;
            color: var(--accent);
        }

        .status-indicator {
            display: inline-block;
            width: 10px;
            height: 10px;
            border-radius: 50%;
            margin-right: 8px;
        }

        .status-active {
            background: var(--success);
            box-shadow: 0 0 10px var(--success);
        }

        .status-inactive {
            background: var(--error);
        }

        .status-partial {
            background: var(--warning);
        }

        .button {
            display: inline-block;
            background: var(--accent);
            color: white;
            padding: 10px 20px;
            border-radius: 5px;
            text-decoration: none;
            margin: 5px;
            transition: background 0.2s;
            border: none;
            cursor: pointer;
            font-size: 1em;
        }

        .button:hover {
            background: #3a8eef;
        }

        .command-box {
            background: #1a1a1a;
            border: 1px solid var(--accent);
            border-radius: 5px;
            padding: 15px;
            margin: 10px 0;
            font-family: 'Courier New', monospace;
            font-size: 0.9em;
            overflow-x: auto;
        }

        .quick-actions {
            display: flex;
            flex-wrap: wrap;
            gap: 10px;
            margin-top: 15px;
        }

        .refresh-button {
            position: fixed;
            bottom: 20px;
            right: 20px;
            background: var(--accent);
            color: white;
            border: none;
            border-radius: 50%;
            width: 60px;
            height: 60px;
            font-size: 1.5em;
            cursor: pointer;
            box-shadow: 0 4px 8px rgba(0,0,0,0.3);
            transition: all 0.2s;
        }

        .refresh-button:hover {
            transform: scale(1.1);
            box-shadow: 0 6px 12px rgba(0,0,0,0.4);
        }

        @keyframes spin {
            from { transform: rotate(0deg); }
            to { transform: rotate(360deg); }
        }

        .spinning {
            animation: spin 1s linear infinite;
        }

        .timestamp {
            text-align: center;
            color: var(--text-secondary);
            font-size: 0.9em;
            margin-top: 30px;
        }
    </style>
</head>
<body>
    <div class="container">
        <header>
            <h1>🚀 Wiki-Linux Interactive Dashboard</h1>
            <p class="subtitle">Real-time system monitoring & quick actions</p>
        </header>

        <div class="grid">
            <!-- System Services -->
            <div class="card">
                <h2>⚙️ System Services</h2>
                <div id="services-status">
                    <p>Loading...</p>
                </div>
            </div>

            <!-- Wiki Statistics -->
            <div class="card">
                <h2>📊 Wiki Statistics</h2>
                <div id="wiki-stats">
                    <div class="stat">
                        <span class="stat-label">Total Pages:</span>
                        <span class="stat-value" id="page-count">Loading...</span>
                    </div>
                    <div class="stat">
                        <span class="stat-label">Git Commits:</span>
                        <span class="stat-value" id="commit-count">Loading...</span>
                    </div>
                    <div class="stat">
                        <span class="stat-label">Disk Usage:</span>
                        <span class="stat-value" id="disk-usage">Loading...</span>
                    </div>
                    <div class="stat">
                        <span class="stat-label">Last Sync:</span>
                        <span class="stat-value" id="last-sync">Loading...</span>
                    </div>
                </div>
            </div>

            <!-- Ollama Models -->
            <div class="card">
                <h2>🤖 Ollama Models</h2>
                <div id="ollama-models">
                    <p>Loading...</p>
                </div>
            </div>
        </div>

        <!-- Quick Actions -->
        <div class="card">
            <h2>⚡ Quick Actions</h2>
            <div class="quick-actions">
                <button class="button" onclick="openWebUI()">🌐 Open Web UI</button>
                <button class="button" onclick="searchWiki()">🔍 Search Wiki</button>
                <button class="button" onclick="createNote()">📝 New Note</button>
                <button class="button" onclick="checkStatus()">✅ Check Status</button>
                <button class="button" onclick="syncGit()">🔄 Sync to Git</button>
                <button class="button" onclick="openObsidian()">📖 Open Obsidian</button>
            </div>
        </div>

        <!-- Command Reference -->
        <div class="card">
            <h2>💻 Quick Commands</h2>
            <div class="command-box">
wiki new "Title"        # Create new note<br>
wiki ask "Question"     # Ask LLM<br>
wiki search "keyword"   # Search wiki<br>
wiki status             # Check status<br>
wiki sync               # Git commit+push<br>
wiki lint               # Check integrity
            </div>
        </div>

        <button class="refresh-button" onclick="refreshData()" title="Refresh Data">
            🔄
        </button>

        <div class="timestamp">
            Last updated: <span id="last-update">Never</span>
        </div>
    </div>

    <script>
        // Configuration
        const config = {
            wikiPath: '/home/sourov/Documents/wiki-linux/wiki-linux',
            webUIUrl: 'http://127.0.0.1:8080',
            refreshInterval: 30000 // 30 seconds
        };

        // Mock data functions (in real implementation, these would call the system)
        async function loadServicesStatus() {
            // Mock service status
            const services = [
                { name: 'wiki-monitor', status: 'active' },
                { name: 'wiki-ollama', status: 'active' },
                { name: 'wiki-openwebui', status: 'active' },
                { name: 'wiki-sync.timer', status: 'active' }
            ];

            const container = document.getElementById('services-status');
            container.innerHTML = services.map(s => {
                const statusClass = s.status === 'active' ? 'status-active' : 'status-inactive';
                return `
                    <div class="stat">
                        <span class="stat-label">
                            <span class="status-indicator ${statusClass}"></span>
                            ${s.name}
                        </span>
                        <span class="stat-value">${s.status.toUpperCase()}</span>
                    </div>
                `;
            }).join('');
        }

        async function loadWikiStats() {
            // Mock statistics (in real implementation, parse wiki files)
            document.getElementById('page-count').textContent = '~150';
            document.getElementById('commit-count').textContent = '~450';
            document.getElementById('disk-usage').textContent = '16M';
            document.getElementById('last-sync').textContent = '2 minutes ago';
        }

        async function loadOllamaModels() {
            // Mock Ollama models
            const models = [
                'mistral:latest',
                'llama3.2:latest',
                'qwen2.5-coder:latest',
                'phi3:latest'
            ];

            const container = document.getElementById('ollama-models');
            container.innerHTML = models.map(m => `
                <div class="stat">
                    <span class="stat-label">${m}</span>
                    <span class="stat-value">READY</span>
                </div>
            `).join('');
        }

        async function refreshData() {
            const button = document.querySelector('.refresh-button');
            button.classList.add('spinning');

            try {
                await Promise.all([
                    loadServicesStatus(),
                    loadWikiStats(),
                    loadOllamaModels()
                ]);

                document.getElementById('last-update').textContent = new Date().toLocaleTimeString();
            } catch (error) {
                console.error('Error refreshing data:', error);
            } finally {
                button.classList.remove('spinning');
            }
        }

        // Quick action functions
        function openWebUI() {
            window.open(config.webUIUrl, '_blank');
        }

        function searchWiki() {
            alert('Open terminal and run: wiki search "keyword"\nOr press Super+Space for search dialog');
        }

        function createNote() {
            alert('Open terminal and run: wiki new "Your Title"');
        }

        function checkStatus() {
            alert('Open terminal and run: wiki status');
        }

        function syncGit() {
            alert('Open terminal and run: wiki sync');
        }

        function openObsidian() {
            alert('Open terminal and run: wiki open');
        }

        // Initialize
        document.addEventListener('DOMContentLoaded', () => {
            refreshData();

            // Auto-refresh every 30 seconds
            setInterval(refreshData, config.refreshInterval);
        });
    </script>
</body>
</html>
