// memory.js — lightweight per-origin action log stored in chrome.storage.local
const KEY = "copilot_memory";

export async function recordAction({ origin, kind, payload }) {
  const store = await _load();
  if (!store[origin]) store[origin] = [];
  store[origin].unshift({ kind, payload, ts: Date.now() });
  store[origin] = store[origin].slice(0, 50); // keep last 50 per origin
  await _save(store);
}

export async function recallForOrigin(origin, limit = 5) {
  const store = await _load();
  return (store[origin] || []).slice(0, limit);
}

async function _load() {
  const api = typeof browser !== "undefined" ? browser : chrome;
  const r = await api.storage.local.get(KEY);
  return r[KEY] || {};
}

async function _save(store) {
  const api = typeof browser !== "undefined" ? browser : chrome;
  await api.storage.local.set({ [KEY]: store });
}

