      .wiki-dismiss { width: 100%; padding: 6px; cursor: pointer; background: var(--interactive-accent); color: var(--text-on-accent); border: none; border-radius: 4px; margin-top: 4px; }
    `;
    document.head.appendChild(style);
  }
