    for f in files:
        fid = f.get("id") or (f.get("file") or {}).get("id")
        if fid:
            _curl("POST", f"/api/v1/knowledge/{kb_id}/file/remove", key, json={"file_id": fid})
    print(f"Cleared {len(files)} existing files from KB.")


def _upload_and_attach(kb_id: str, key: str, md_path: Path) -> str | None:
    """Upload file and attach to KB. Returns file_id or None on error."""
    resp = _curl("POST", "/api/v1/files/", key, file_path=str(md_path))
    file_id = resp.get("id")
    if not file_id:
        print(f"  WARN: upload failed for {md_path.name}: {resp.get('_raw','?')}")
        return None
    resp2 = _curl("POST", f"/api/v1/knowledge/{kb_id}/file/add", key, json={"file_id": file_id})
    if resp2.get("name") == KB_NAME or resp2.get("id") == kb_id:
        return file_id
    print(f"  WARN: attach failed for {md_path.name}: {resp2.get('detail','?')}")
    return file_id  # uploaded but attach may have failed — keep in ledger


# ── Commands ─────────────────────────────────────────────────────────────────

def cmd_status(key: str):
    kb_id = _get_or_create_kb(key)
    resp = _curl("GET", f"/api/v1/knowledge/{kb_id}", key)
    files = resp.get("files") or []
    ledger = _load_ledger()
    md_files = _collect_md_files()
    print(f"KB:           {KB_NAME} ({kb_id})")
    print(f"Files in KB:  {len(files)}")
    print(f"Wiki MD files:{len(md_files)}")
    print(f"Synced:       {len(ledger)}")
    stale = [f for f in md_files if _file_hash(f) != ledger.get(str(f.relative_to(WIKI_ROOT)), {}).get("hash")]
    print(f"Stale/new:    {len(stale)}")


def cmd_sync(key: str, full: bool = False):
    kb_id = _get_or_create_kb(key)
    ledger = _load_ledger()
    md_files = _collect_md_files()

    if full:
        _delete_all_kb_files(kb_id, key)
        ledger = {}

    to_sync = []
    for f in md_files:
        rel = str(f.relative_to(WIKI_ROOT))
        h = _file_hash(f)
        if full or ledger.get(rel, {}).get("hash") != h:
            to_sync.append((f, rel, h))

    if not to_sync:
        print(f"KB up to date. {len(md_files)} files, nothing to sync.")
        return

    print(f"Syncing {len(to_sync)}/{len(md_files)} files to '{KB_NAME}'...")
    ok = 0
    for i, (path, rel, h) in enumerate(to_sync, 1):
        print(f"  [{i}/{len(to_sync)}] {rel}", end=" ", flush=True)
        # Remove old version if incremental
        if not full and rel in ledger:
            old_fid = ledger[rel].get("file_id")
            if old_fid:
                _curl("POST", f"/api/v1/knowledge/{kb_id}/file/remove", key, json={"file_id": old_fid})
        fid = _upload_and_attach(kb_id, key, path)
        if fid:
            ledger[rel] = {"hash": h, "file_id": fid, "synced_at": int(time.time())}
            ok += 1
            print("✓")
        else:
            print("✗")
        time.sleep(0.3)  # gentle rate limit

    _save_ledger(ledger)
    print(f"\nDone: {ok}/{len(to_sync)} synced. Ledger → {LEDGER_PATH}")


# ── Main ──────────────────────────────────────────────────────────────────────

def main():
    parser = argparse.ArgumentParser(description="Sync wiki markdown → OpenWebUI knowledge base")
    parser.add_argument("--full",   action="store_true", help="Wipe KB and re-upload all files")
    parser.add_argument("--status", action="store_true", help="Show stats only")
    args = parser.parse_args()

    key = _get_api_key()

    if args.status:
        cmd_status(key)
    elif args.full:
        cmd_sync(key, full=True)
    else:
        cmd_sync(key, full=False)


if __name__ == "__main__":
    main()
"}

